+type Clause = {
+  patterns: Pattern<any>[];
+  predicate?: (value: any) => unknown;
+  handler: (selection: unknown, value: any) => unknown;
+};
+
+type Step = Clause | { tap: (result: unknown) => void };
+
+const noInput = Symbol('matchEach no input');
+
+/**
+ * Creates a pattern matching expression which invokes every matching handler.
+ */
+export function matchEach<const input, output = symbols.unset>(value: input): MatchEach<input, output>;
+export function matchEach<input, output = symbols.unset>(): MatchEach<input, output>;
+export function matchEach(value: unknown = noInput): MatchEach<any, any> {
+  return new MatchEachExpression(value, []) as any;
+}
+
+class MatchEachExpression {
+  constructor(private input: unknown, private steps: readonly Step[]) {}
+
+  with(...args: any[]): MatchEachExpression {
+    const handler = args[args.length - 1];
+    const patterns: Pattern<any>[] = [args[0]];
+    let predicate: ((value: unknown) => unknown) | undefined;
+
+    if (args.length === 3 && typeof args[1] === 'function') {
+      predicate = args[1];
+    } else if (args.length > 2) {
+      patterns.push(...args.slice(1, -1));
+    }
+
+    return new MatchEachExpression(this.input, [...this.steps, { patterns, predicate, handler }]);
+  }
+
+  when(predicate: (value: unknown) => unknown, handler: (value: unknown) => unknown): MatchEachExpression {
+    return this.with(Pattern.any, predicate, handler);
+  }
+
+  tap(callback: (result: unknown) => void): MatchEachExpression {
+    return new MatchEachExpression(this.input, [...this.steps, { tap: callback }]);
+  }
+
+  otherwise(handler: (value: unknown) => unknown): unknown[] {
+    const results = this.evaluate(this.input);
+    return results.length ? results : [handler(this.input)];
+  }
+
+  exhaustive(handler = defaultCatcher): unknown[] {
+    const results = this.evaluate(this.input);
+    return results.length ? results : [handler(this.input)];
+  }
+
+  run(): unknown[] {
+    const results = this.evaluate(this.input);
+    if (results.length) return results;
+    return defaultCatcher(this.input);
+  }
+
+  returnType(): this { return this; }
+
+  narrow(): this { return this; }
+
+  toFunction(): (input: unknown) => unknown[] {
+    return (input) => {
